  CONSTRAINT `pending_sales_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `models` (`id`) ON DELETE CASCADE,
  CONSTRAINT `pending_sales_seller_id_foreign` FOREIGN KEY (`seller_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=latin1;
